use strict;
use warnings;
use PDF::API2;
use PDF::Text::Simple;
use Scalar::Util qw(blessed);

# Function to extract text from a PDF
sub extract_text {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $text_extractor = PDF::Text::Simple->new($pdf);
    my $text = $text_extractor->text;

    return $text;
}

# Function to parse the extracted text for specific information
sub parse_text {
    my ($text) = @_;
    my @info;

    # Example regular expressions to find date, author, and table information
