        push @info, "Date: $1";
    }
    if ($text =~ /Author: ([\w\s]+)/) {
        push @info, "Author: $1";
    }
    if ($text =~ /Table\s*(\d+)/) {
        push @info, "Table: $1";
    }

    return @info;
}

